(self.webpackChunkcheatsheet=self.webpackChunkcheatsheet||[]).push([[767],{4325:(n,a,s)=>{"use strict";s.r(a),s.d(a,{data:()=>e});const e={key:"v-07df014d",path:"/python/data-type/dictionary/",title:"Dictionary",lang:"en-US",frontmatter:{},excerpt:"",headers:[{level:2,title:"สร้าง dictionary",slug:"สร้าง-dictionary",children:[{level:3,title:"สร้าง Dictionary เปล่าๆ",slug:"สร้าง-dictionary-เปล่าๆ",children:[]},{level:3,title:"สร้าง dictionary โดยการเขียนเอง",slug:"สร้าง-dictionary-โดยการเขียนเอง",children:[]}]},{level:2,title:"เรียกข้อมูลมาจาก Dictionary",slug:"เรียกข้อมูลมาจาก-dictionary",children:[{level:3,title:"แบบเหมือน Lists",slug:"แบบเหมือน-lists",children:[]},{level:3,title:"แบบใช้ methods",slug:"แบบใช้-methods",children:[]}]},{level:2,title:"เพื่มค่าเข้าใปใน Dictionary",slug:"เพื่มค่าเข้าใปใน-dictionary",children:[]},{level:2,title:"ลบค่าออกจาก Dictionary",slug:"ลบค่าออกจาก-dictionary",children:[{level:3,title:"ลบค่าบางตัวออกจาก Dictionary",slug:"ลบค่าบางตัวออกจาก-dictionary",children:[]},{level:3,title:"ลบค่าทุกตัวออกจาก Dictionary",slug:"ลบค่าทุกตัวออกจาก-dictionary",children:[]},{level:3,title:"ลบความเป็น Dictionary ออกไป",slug:"ลบความเป็น-dictionary-ออกไป",children:[]}]},{level:2,title:"เช็คค่า Keys และ Values ที่อยู่ใน Dictionary",slug:"เช็คค่า-keys-และ-values-ที่อยู่ใน-dictionary",children:[]}],filePathRelative:"python/data-type/dictionary/README.md",git:{updatedTime:162676698e4,contributors:[]}}},9158:(n,a,s)=>{"use strict";s.r(a),s.d(a,{default:()=>t});const e=(0,s(6252).uE)('<h1 id="dictionary" tabindex="-1"><a class="header-anchor" href="#dictionary" aria-hidden="true">#</a> Dictionary</h1><p>Dictionary เป็นการเก็บข้อมูลประเภทหนึ่ง ซึ่งจะมีความคล้ายคลึงกับการเก็บตัวแปรหลายๆอันเข้าไปสู่ตัวแปรเดียวกัน</p><p>โดย Dictionary จะมีข้อมูลอยู่ 2 ประเภท นั่นคือ</p><ul><li>Key (พูดง่ายๆก็คือตัวแปร)</li><li>Value (พูดง่ายๆก็คือค่าที่อยู่ในตัวแปร)</li></ul><p>แต่ว่า Dictionary สามารถเก็บข้อมูล (Key และ Value) ได้หลายๆอัน ทำให้น้องๆสามารถเรียกค่า (Key) เพื่อเอาผลลัพท์ (Value) ได้</p><p>โดยน้องๆมีหลาย Key ก็ได้ แต่อาจจะไม่มี Value (ก็คือปล่อยให้ค่า Value เป็น None หรือว่า Null)</p><hr><h2 id="สร้าง-dictionary" tabindex="-1"><a class="header-anchor" href="#สร้าง-dictionary" aria-hidden="true">#</a> สร้าง dictionary</h2><h3 id="สร้าง-dictionary-เปล่าๆ" tabindex="-1"><a class="header-anchor" href="#สร้าง-dictionary-เปล่าๆ" aria-hidden="true">#</a> สร้าง Dictionary เปล่าๆ</h3><p>น้องสามารถสร้างตัว Dictionary ใหม่โดยการใช้ฟังก์ชั่น <code>dict()</code> เพื่อเปลี่ยนตัวแปรให้เก็บข้อมูลแบบ Dictionary และสร้่าง dictionary เปล่าๆขึ้นมา 1 อัน</p><p>ตัวอย่างการเขียน</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>my_dictionary <span class="token operator">=</span> <span class="token builtin">dict</span><span class="token punctuation">(</span><span class="token punctuation">)</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><h3 id="สร้าง-dictionary-โดยการเขียนเอง" tabindex="-1"><a class="header-anchor" href="#สร้าง-dictionary-โดยการเขียนเอง" aria-hidden="true">#</a> สร้าง dictionary โดยการเขียนเอง</h3><p>โดยฝั่งซ้ายจะเป็นค่า key และฝั่งขวาจะเป็นค่า value</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>my_dictionary <span class="token operator">=</span> <span class="token punctuation">{</span>\n<span class="token string">&quot;happy&quot;</span> <span class="token punctuation">:</span> <span class="token number">20</span><span class="token punctuation">,</span>\n<span class="token string">&quot;not happy&quot;</span> <span class="token punctuation">:</span> <span class="token number">30</span><span class="token punctuation">,</span>\n<span class="token string">&quot;sad&quot;</span> <span class="token punctuation">:</span> <span class="token boolean">False</span>\n<span class="token punctuation">}</span>\n\nmy_dictionary <span class="token operator">=</span> <span class="token punctuation">{</span><span class="token string">&quot;happy&quot;</span> <span class="token punctuation">:</span> <span class="token number">20</span><span class="token punctuation">,</span> <span class="token string">&quot;not happy&quot;</span> <span class="token punctuation">:</span> <span class="token number">30</span><span class="token punctuation">,</span> <span class="token string">&quot;sad&quot;</span> <span class="token punctuation">:</span> <span class="token boolean">False</span><span class="token punctuation">}</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>โดยน้องๆอาจจะเขียนแบบที่ 1 ที่จะแยกบรรทัด หรือเขียนแบบบรรทัดเดียวกันก็ได้ครับ</p><p>แต่เขียนไปเป็นหลายบรรทัด น้องๆจะอ่านมันได้ง่ายขึ้นครับ จึงเหมาะกับน้องๆที่ไม่ชอบอ่านโค้ดยากๆ ยาวๆ</p><hr><h2 id="เรียกข้อมูลมาจาก-dictionary" tabindex="-1"><a class="header-anchor" href="#เรียกข้อมูลมาจาก-dictionary" aria-hidden="true">#</a> เรียกข้อมูลมาจาก Dictionary</h2><h3 id="แบบเหมือน-lists" tabindex="-1"><a class="header-anchor" href="#แบบเหมือน-lists" aria-hidden="true">#</a> แบบเหมือน Lists</h3><p>ก็สามารถเรียกเหมือน List ได้เลย แต่การเรียกจะใส่เป็น Key แทน ไม่เหมือน List ที่จะใส่เป็นลำดับของข้อมูล</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>my_dictionary<span class="token punctuation">[</span><span class="token string">&#39;happy&#39;</span><span class="token punctuation">]</span> <span class="token comment"># Returns 20</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><p>หรือน้องๆอาจจะเช็คก่อนว่ามี key นั้นๆอยู่หรือเปล่าโดยการใช้ keyword <code>in</code></p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code><span class="token string">&quot;happy&quot;</span> <span class="token keyword">in</span> my_dictionary <span class="token comment"># Return true</span>\n<span class="token number">20</span> <span class="token keyword">in</span> my_dictionary <span class="token comment"># Return true</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>หากคืนกลับมาเป็น True (เหมือนกับตัวอย่าง) ก็จะบอกได้ว่ามี Key ที่ชื่อนั้นอยู่ใน dictionary นั้นๆ</p><h3 id="แบบใช้-methods" tabindex="-1"><a class="header-anchor" href="#แบบใช้-methods" aria-hidden="true">#</a> แบบใช้ methods</h3><p>ในแบบนี้ น้องๆก็จะได้ใช้ <code>.get()</code> และ <code>.setdefault()</code> ทำให้น้องๆอาจจะจัดการกับ Key ที่ไม่เคยอยู่จริงก็ได้ครับ</p><p>การใช้ <code>.get()</code> ก็เหมือนกับการเรียกถามหา Value จากค่า Key ที่น้องให้มาเลย แต่จะแตกต่างออกไปคือ หากว่ามันหาแล้วไม่เจอ ก็จะคืนค่า <code>None</code> กลับมาแทน</p><p>ตัวอย่างเช่น</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>my_dict<span class="token punctuation">.</span>get<span class="token punctuation">(</span><span class="token string">&#39;Kuma&#39;</span><span class="token punctuation">)</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><p>แต่หากว่าน้องๆไม่ต้องการที่จะขอคืนเป็น Null ก็สามารถใส่ Parameter <code>default</code> เข้าไปด้วยก็ได้ครับ เช่นว่า หากไม่เจอ ก็ให้คืนเป็น 0</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>my_dict<span class="token punctuation">.</span>get<span class="token punctuation">(</span><span class="token string">&#39;Kuma&#39;</span><span class="token punctuation">,</span> default <span class="token operator">=</span> <span class="token number">0</span><span class="token punctuation">)</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><p>และสำหรับ <code>.setdefault()</code> ก็จะเหมือนกับ <code>.get()</code> เลย แต่ว่าจะใส่ค่าที่น้องเคยหาเข้าไปใน dictionary ด้วย เหมือนมันสร้างว่า key ที่น้องหา เท่ากับ None แล้วก็เอาไปเก็บไว้ใน dictionary แล้วก็ค่อยเรียกค่านั้นอีกรอบ</p><hr><h2 id="เพื่มค่าเข้าใปใน-dictionary" tabindex="-1"><a class="header-anchor" href="#เพื่มค่าเข้าใปใน-dictionary" aria-hidden="true">#</a> เพื่มค่าเข้าใปใน Dictionary</h2><p>ถ้าน้องๆต้องการเพื่มค่าเข้าไปใน Dictionary ก็สามารถทำการเพื่ม ด้วยการเขียน</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code><span class="token operator">&lt;</span>variableName<span class="token operator">&gt;</span><span class="token punctuation">[</span><span class="token operator">&lt;</span>key<span class="token operator">&gt;</span><span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token operator">&lt;</span>value<span class="token operator">&gt;</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><p>เช่นว่าพี่ต้องการบอกให้ <code>kumamon = 12</code> และไปอยู่ในตัวแปร dictionary ที่ชื่อว่า <code>my_dict</code> ก็จะเขียนได้ดังนี้ครับ</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>my_dict<span class="token punctuation">[</span><span class="token string">&#39;kumamon&#39;</span><span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token number">12</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><hr><h2 id="ลบค่าออกจาก-dictionary" tabindex="-1"><a class="header-anchor" href="#ลบค่าออกจาก-dictionary" aria-hidden="true">#</a> ลบค่าออกจาก Dictionary</h2><p>โดยน้องๆสามารถที่จะลบ</p><ul><li>ทุกตัว</li><li>ตัวที่น้องเลือก</li><li>ลบความเป็น Dictionary ออกไป</li></ul><h3 id="ลบค่าบางตัวออกจาก-dictionary" tabindex="-1"><a class="header-anchor" href="#ลบค่าบางตัวออกจาก-dictionary" aria-hidden="true">#</a> ลบค่าบางตัวออกจาก Dictionary</h3><p>น้องๆสามารถใช้ keyword <code>del</code> เพื่อทำการลบค่าออกไปครับ ตัวอย่างเช่น</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code><span class="token keyword">del</span> my_dict<span class="token punctuation">[</span><span class="token string">&#39;Kumamon&#39;</span><span class="token punctuation">]</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><p>มันก็จะทำการลบค่า Key + Value ที่ Key มีค่าเท่ากับ &#39;Kumamon&#39; ออกไป<br> เหมือนกับว่ามันไม่เคยเกิดขึ้นมาก่อนเลย</p><h3 id="ลบค่าทุกตัวออกจาก-dictionary" tabindex="-1"><a class="header-anchor" href="#ลบค่าทุกตัวออกจาก-dictionary" aria-hidden="true">#</a> ลบค่าทุกตัวออกจาก Dictionary</h3><p>น้องๆสามารถใช้ method <code>.clear()</code> เพื่อทำการล้างค่า Key + Value ออกไป ทำให้ตัวแปรเป็น Dictionary เปล่าๆ</p><p>ตัวอย่างการเขียน</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>my_dict<span class="token punctuation">.</span>clear<span class="token punctuation">(</span><span class="token punctuation">)</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><h3 id="ลบความเป็น-dictionary-ออกไป" tabindex="-1"><a class="header-anchor" href="#ลบความเป็น-dictionary-ออกไป" aria-hidden="true">#</a> ลบความเป็น Dictionary ออกไป</h3><p>เหมือนทำให้ตัวแปรนั้นเก็บเป็นค่า None ไปเลย พูดง่ายๆก็คือที้งมันไปเลย โดยการใช้ keyword <code>del</code></p><p>ตัวอย่างการใช้งาน</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code><span class="token keyword">del</span> my_dict\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><p>ก็จะทำให้เวลาน้องเรียกตัวแปร my_dict ก็จะขึ้นแบบน้ีครับ</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>Traceback (most recent call last):\n  File &quot;&lt;stdin&gt;&quot;, line 1, in &lt;module&gt;\nNameError: name &#39;mydict&#39; is not defined\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>เพราะการใช้ <code>del</code> เป็นการลบตัวแปรออกไปเลย ไม่เหมือนการเขียน <code>my_dict = None</code> นะครับ เพราะว่าอันนั้น ตัวแปรยังอยู่</p><hr><h2 id="เช็คค่า-keys-และ-values-ที่อยู่ใน-dictionary" tabindex="-1"><a class="header-anchor" href="#เช็คค่า-keys-และ-values-ที่อยู่ใน-dictionary" aria-hidden="true">#</a> เช็คค่า Keys และ Values ที่อยู่ใน Dictionary</h2><p>น้องๆสามารถใช้ <code>.keys()</code> สำหรับการดูค่า keys ทั้งหมดใน Dictionary<br> และใช้ <code>.values()</code> เพื่อดูค่า values ทั้งหมดใน Dictionary</p><p>ตัวอย่างการใช้งาน</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>my_dictionary <span class="token operator">=</span> <span class="token punctuation">{</span><span class="token string">&quot;happy&quot;</span> <span class="token punctuation">:</span> <span class="token number">20</span><span class="token punctuation">,</span> <span class="token string">&quot;not happy&quot;</span> <span class="token punctuation">:</span> <span class="token number">30</span><span class="token punctuation">,</span> <span class="token string">&quot;sad&quot;</span> <span class="token punctuation">:</span> <span class="token boolean">False</span><span class="token punctuation">}</span>\n\n<span class="token keyword">print</span><span class="token punctuation">(</span>my_dictionary<span class="token punctuation">.</span>keys<span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span>\n<span class="token keyword">print</span><span class="token punctuation">(</span>my_dictionary<span class="token punctuation">.</span>values<span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>ก็จะออกมาเป็น</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>dict_keys([&#39;happy&#39;, &#39;not happy&#39;, &#39;sad&#39;])\ndict_values([20, 30, False])\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>โดยมันคืนออกมาเป็นตัวแปรประเภท <code>dict_keys</code> และ <code>dict_values</code> นั่นเอง น้องจะยังไม่สามารถเอาข้อมูลที่น้องขอมา เพื่อเอาไปใช้ได้นะครับ</p>',66),t={render:function(n,a){return e}}}}]);